    public class Listview1Adapter extends BaseAdapter {
        ArrayList<HashMap<String, Object>> _data;

        public Listview1Adapter(ArrayList<HashMap<String, Object>> arrayList) {
            this._data = arrayList;
        }

        @Override
        public int getCount() {
            return this._data.size();
        }

        @Override
        public HashMap<String, Object> getItem(int i) {
            return this._data.get(i);
        }

        @Override
        public long getItemId(int i) {
            return i;
        }

        @Override
        public View getView(int i, View view, ViewGroup viewGroup) {
            LayoutInflater layoutInflater = (LayoutInflater) BookViewActivity.this.getBaseContext().getSystemService(Context.LAYOUT_INFLATER_SERVICE);
            if (view == null) {
                view = layoutInflater.inflate(R.layout.sample, (ViewGroup) null);
            }
            LinearLayout linearLayout = view.findViewById(R.id.linear1);
            LinearLayout linearLayout2 = view.findViewById(R.id.linear_circle);
            LinearLayout linearLayout3 = view.findViewById(R.id.linear3);
            ImageView imageView = view.findViewById(R.id.imageview1);
            TextView textView = view.findViewById(R.id.textview2);
            TextView textView2 = view.findViewById(R.id.main_titel_textview);
            TextView textView3 = view.findViewById(R.id.textview3);
            textView2.setText(Objects.requireNonNull(this._data.get(i).get("content")).toString());
            @SuppressLint("ResourceType") Animation loadAnimation = AnimationUtils.loadAnimation(BookViewActivity.this.getApplicationContext(), 17432578);
            loadAnimation.setDuration(200L);
            linearLayout.startAnimation(loadAnimation);
            if (((HashMap<?, ?>) BookViewActivity.this.map_list.get(i)).containsKey("item")) {
                textView3.setText("মোট কন্টেন্ট ".concat(Objects.requireNonNull(this._data.get(i).get("item")).toString().concat(" টি")));
                textView3.setVisibility(View.VISIBLE);
            } else {
                textView3.setVisibility(View.GONE);
            }
            if (!BookViewActivity.this.data.getString("theme", "").equals("theme4th_unused")) {
                if (!BookViewActivity.this.data.getString("theme", "").equals("night_theme")) {
                    if (BookViewActivity.this.data.getString("theme", "").equals("theme_2nd_unused")) {

                        BookViewActivity.this._radius(linearLayout, BookViewActivity.this.colorPrimary, 20.0d);
                        BookViewActivity.this._radius(linearLayout2, BookViewActivity.this.colorPrimaryDark, 180.0d);
                        textView2.setTextColor(Color.parseColor(BookViewActivity.this.ColorText));
                        textView.setTextColor(Color.parseColor(BookViewActivity.this.ColorText));
                        textView3.setTextColor(Color.parseColor(BookViewActivity.this.ColorText));
                    } else {
                        linearLayout.setBackgroundResource(R.drawable.rabbi_cropped2);

                        //  BookViewActivity.this._radius(linearLayout, BookViewActivity.this.colorPrimary, 20.0d);
                        textView2.setTextColor(Color.parseColor(BookViewActivity.this.ColorText));
                        textView3.setTextColor(Color.parseColor(BookViewActivity.this.ColorText));
                    }
                } else {

                    linearLayout.setBackgroundResource(R.drawable.rabbi_cropped2);
                    //  BookViewActivity.this._radius(linearLayout, BookViewActivity.this.colorPrimary, 20.0d);
                    textView2.setTextColor(Color.parseColor(BookViewActivity.this.ColorText));
                    textView3.setTextColor(Color.parseColor(BookViewActivity.this.ColorText));
                }
            } else {

                //  BookViewActivity.this._radius(linearLayout, BookViewActivity.this.colorPrimaryDark, 20.0d);
                BookViewActivity.this._radius(linearLayout2, "#E0E0E0", 180.0d);
                textView2.setTextColor(Color.parseColor("#000000"));
                textView.setTextColor(Color.parseColor("#000000"));
                textView3.setTextColor(Color.parseColor("#000000"));
            }
            return view;
        }
    }

        public void craeteData(String name) {
        JSONArray array = new JSONArray();

        for (int i = 0; i < map_list.size(); i++) {
            JSONObject object = new JSONObject();
            try {
                object.put("title", map_list.get(i).get("title"));
                object.put("body", map_list.get(i).get("content"));
            } catch (JSONException e) {
                throw new RuntimeException(e);
            }
            array.put(object);
        }
        File root = getCacheDir();
        File gpxfile = new File(root, name + ".txt");
        FileWriter writer = null;
        try {
            writer = new FileWriter(gpxfile);
            writer.append(array.toString());
            writer.flush();
            writer.close();
        } catch (IOException e) {
            throw new RuntimeException(e);
        }
        Log.e("DATA", array.toString());
    }


